#nullable enable // autogenerated

using System;
using UnityEngine;

namespace MVZ2.Talk
{
    public class CharacterPortrait : IDisposable
    {
        public CharacterPortrait(CharacterPortraitComponent component)
        {
            texture2d = new Texture2D(1, 1);
            this.component = component;
            component.gameObject.SetActive(false);
        }
        public void ChangeVariant(CharacterPortraitViewData viewData)
        {
            var width = viewData.width;
            var height = viewData.height;

            var cameraRT = RenderTexture.GetTemporary(width, height);
            component.gameObject.SetActive(true);
            component.SetRenderTexture(cameraRT);
            component.ChangeVariant(viewData);
            component.Render();
            component.gameObject.SetActive(false);

            var scaledWidth = Mathf.Max(1, Mathf.CeilToInt(viewData.width * TextureScale));
            var scaledHeight = Mathf.Max(1, Mathf.CeilToInt(viewData.height * TextureScale));
            RenderTexture targetRT = cameraRT;
            if (TextureScale != 1)
            {
                var newTargetRT = RenderTexture.GetTemporary(scaledWidth, scaledHeight);
                Graphics.Blit(targetRT, newTargetRT);
                RenderTexture.ReleaseTemporary(targetRT);
                targetRT = newTargetRT;
            }
            texture2d.Reinitialize(scaledWidth, scaledHeight);

            RenderTexture previous = RenderTexture.active;

            RenderTexture.active = targetRT;
            texture2d.ReadPixels(new Rect(0, 0, scaledWidth, scaledHeight), 0, 0);
            texture2d.Apply();
            RenderTexture.active = previous;

            RenderTexture.ReleaseTemporary(targetRT);


            if (sprite.Exists())
            {
                UnityEngine.Object.Destroy(sprite);
                sprite = null;
            }
        }
        public void Dispose()
        {
            if (texture2d.Exists()) 
                UnityEngine.Object.Destroy(texture2d);
            if (sprite.Exists())
                UnityEngine.Object.Destroy(sprite);
            component.DestroyGameObject();
        }
        public Texture2D GetTexture2D()
        {
            return texture2d;
        }
        public Sprite GetSprite()
        {
            if (!sprite.Exists())
            {
                sprite = Sprite.Create(texture2d, new Rect(0, 0, texture2d.width, texture2d.height), Vector2.one * 0.5f);
            }
            return sprite;
        }
        public float TextureScale { get; set; } = 1f;
        private Texture2D texture2d;
        private Sprite? sprite;
        private CharacterPortraitComponent component;
    }
}
